DO $migrate_rename_lesson_section_to_course_section$ BEGIN
  IF EXISTS (
    SELECT 1
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'public' AND c.relkind = 'r' AND c.relname = 'lesson_section'
  ) AND NOT EXISTS (
    SELECT 1
    FROM pg_class c2
    JOIN pg_namespace n2 ON n2.oid = c2.relnamespace
    WHERE n2.nspname = 'public' AND c2.relkind = 'r' AND c2.relname = 'course_section'
  ) THEN
    ALTER TABLE public.lesson_section RENAME TO course_section;
  END IF;
END;
