DO $add_exercise_course_fk$
BEGIN
  IF EXISTS (SELECT 1 FROM pg_tables WHERE tablename = 'exercise' AND schemaname = 'public')
     AND NOT EXISTS (
       SELECT 1 FROM pg_constraint co
       JOIN pg_class rel ON rel.oid = co.conrelid
       JOIN pg_namespace n ON n.oid = rel.relnamespace
       WHERE n.nspname = 'public' AND rel.relname = 'exercise' AND co.contype = 'f' AND co.conname = 'exercise_course_id_fkey'
     ) THEN
    ALTER TABLE public.exercise ADD CONSTRAINT exercise_course_id_fkey FOREIGN KEY ("course_id") REFERENCES public.course("id") ON DELETE no action ON UPDATE no action;
  END IF;
END;
$add_exercise_course_fk$;--> statement-breakpoint
